const NAV_URLS = [
  'https://jena-digital.de/',
  'https://jena-digital.de/ueber-uns',
  'https://jena-digital.de/ueber-uns/unsere-mitglieder',
  'https://jena-digital.de/ueber-uns/mitglied-werden',
  'https://jena-digital.de/ueber-uns/aktuelles',
  'https://jena-digital.de/ueber-uns/jobs-bei-uns',
  'https://jena-digital.de/unser-oekosystem/fachgruppen-arbeitskreise',
  'https://jena-digital.de/unser-team',
  'https://jena-digital.de/veranstaltungen',
  'https://jena-digital.de/veranstaltungen/archiv',
  'https://jena-digital.de/jedi',
  'https://jena-digital.de/dehub',
  'https://jena-digital.de/jobs',
  'https://jena-digital.de/impressum',
];

const html = $json.data || '';
const articlePattern = /href="(\/ueber-uns\/aktuelles\/detail\/[^"?#]+)"/g;
const discovered = new Set();
let m;
while ((m = articlePattern.exec(html)) !== null) {
  discovered.add('https://jena-digital.de' + m[1]);
}

const allUrls = [...NAV_URLS, ...discovered];
return allUrls.map(url => ({ json: { url } }));

const url = $('Build URL List').item.json.url;
const html = $json.data || '';

function stripHtml(h) {
  return h
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<nav[\s\S]*?<\/nav>/gi, '')
    .replace(/<header[\s\S]*?<\/header>/gi, '')
    .replace(/<footer[\s\S]*?<\/footer>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<[^>]+>/g, '\n')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#\d+;/g, '')
    .replace(/\n{3,}/g, '\n\n').trim();
}

function extractTitle(h) {
  const m = h.match(/<h1[^>]*>([^<]+)<\/h1>/i) || h.match(/<title[^>]*>([^<]+)<\/title>/i);
  return m ? m[1].replace(/ [-|] Jena Digital.*$/i, '').trim() : '';
}

function classifyDocType(u) {
  if (u.includes('/aktuelles/detail/')) return 'news_article';
  if (u.includes('/veranstaltungen')) return 'event';
  if (u.includes('mitglied-werden') || u.includes('satzung')) return 'legal_doc';
  return 'org_page';
}

if (!html || $json.error || html.includes('Seite nicht gefunden')) return [];

const content = stripHtml(html);
const title = extractTitle(html);
const dateMatch = content.match(/\b(\d{1,2}\.\d{1,2}\.\d{4})\b/);
const date = dateMatch ? dateMatch[1] : null;
const doc_type = classifyDocType(url);

// Pure JS hash (kein require, kein crypto global nötig)
function hashStr(str) {
  let h1 = 0xdeadbeef, h2 = 0x41c6ce57;
  for (let i = 0; i < str.length; i++) {
    const ch = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ ch, 2654435761);
    h2 = Math.imul(h2 ^ ch, 1597334677);
  }
  h1 = Math.imul(h1 ^ (h1>>>16), 2246822507) ^ Math.imul(h2 ^ (h2>>>13), 3266489909);
  h2 = Math.imul(h2 ^ (h2>>>16), 2246822507) ^ Math.imul(h1 ^ (h1>>>13), 3266489909);
  return (4294967296 * (2097151 & h2) + (h1>>>0)).toString(16).padStart(16,'0');
}
const content_hash = hashStr(content);

return [{ json: { url, title, content, content_hash, date, doc_type } }];

// ── Alle Parameter aus der gepaarten Seite ───────────────────────
const page = $('Extract & Hash').item.json;
const TARGET_LEAF = 96, MAX_LEAF = 220, MAX_W = 384, OVERLAP = 38;

// ── Text-Cleaning (ports aus rag_processor.py) ────────────────────
function cleanText(text) {
  const NOISE = [/mehr erfahren/gi,/Jetzt anmelden/gi,/zur Anmeldung/gi,/hier klicken/gi,/Cookie.*?akzeptieren/gi];
  for (const p of NOISE) text = text.replace(p, '');
  const lines = text.split('\n');
  const res = [];
  for (const line of lines) {
    const s = line.trim();
    if (!s) { res.push(''); continue; }
    if (res.length && res[res.length-1] &&
        res[res.length-1].split(/\s+/).length < 6 &&
        !res[res.length-1].trimEnd().match(/[.!?:;]$/)) {
      res[res.length-1] = res[res.length-1].trimEnd() + ' ' + s;
    } else { res.push(s); }
  }
  return res.join('\n').replace(/\n{3,}/g,'\n\n').replace(/ {2,}/g,' ').trim();
}

// ── Satz-Splitter (Deutsch) ───────────────────────────────────────
function splitSentences(text) {
  return text.split(/(?<=[.!?])\s+(?=[A-ZÜÄÖA-Z])/).map(s=>s.trim()).filter(s=>s.length>20);
}

// ── Sentence Window (für news_article) ───────────────────────────
function sentenceWindowChunks(text) {
  const raw = splitSentences(text);
  const sents = [];
  for (const s of raw) {
    if (sents.length && s.split(/\s+/).length < 8) {
      sents[sents.length-1] = sents[sents.length-1].replace(/\.\s*$/,'') + ' ' + s;
    } else sents.push(s);
  }
  return sents.map((s,i) => ({
    text: s,
    context_window: sents.slice(Math.max(0,i-2), Math.min(sents.length,i+3)).join(' '),
    chunk_strategy: 'sentence_window'
  }));
}

// ── Fixed-Size (für event) ────────────────────────────────────────
function fixedSizeChunks(text) {
  const words = text.split(/\s+/);
  const chunks = [];
  let start=0, idx=0;
  while (start < words.length) {
    const end = Math.min(start+MAX_W, words.length);
    const t = words.slice(start,end).join(' ');
    chunks.push({ text:t, context_window:t, chunk_strategy:'fixed_size', chunk_index:idx });
    if (end===words.length) break;
    start += MAX_W - OVERLAP; idx++;
  }
  chunks.forEach(c => c.total_chunks=chunks.length);
  return chunks;
}

// ── Hierarchical (für org_page + legal_doc) ───────────────────────
function splitSections(text) {
  const lines = text.split('\n');
  const secs = [];
  let heading='Einleitung', body=[];
  for (const line of lines) {
    const s=line.trim(); if(!s) continue;
    const isH = s.length<=80 && !s.match(/[.,;:]$/) && s[0]===s[0].toUpperCase() && s.split(/\s+/).length<=10;
    if (isH && body.length) { secs.push({heading,body:body.join('\n')}); heading=s; body=[]; }
    else body.push(s);
  }
  if (body.length) secs.push({heading,body:body.join('\n')});
  return secs;
}

function splitOversized(text) {
  const words=text.split(/\s+/); const parts=[]; let start=0;
  while(start<words.length) {
    const end=Math.min(start+MAX_LEAF,words.length);
    parts.push(words.slice(start,end).join(' '));
    if(end===words.length) break;
    start+=MAX_LEAF-OVERLAP;
  }
  return parts;
}

function mergeToLeafNodes(paragraphs) {
  const expanded=[];
  for (const p of paragraphs) {
    if(p.split(/\s+/).length>MAX_LEAF) expanded.push(...splitOversized(p));
    else expanded.push(p);
  }
  const nodes=[]; let parts=[], words=0;
  for (const p of expanded) {
    const pw=p.split(/\s+/).length;
    if(!words) { parts.push(p); words=pw; }
    else if(words+pw<=MAX_LEAF) {
      parts.push(p); words+=pw;
      if(words>=TARGET_LEAF) { nodes.push(parts.join('\n\n')); parts=[]; words=0; }
    } else { nodes.push(parts.join('\n\n')); parts=[p]; words=pw; }
  }
  if(parts.length) nodes.push(parts.join('\n\n'));
  return nodes;
}

function hierarchicalChunks(text, pageTitle) {
  const chunks=[];
  const sections=splitSections(text);
  for(let si=0;si<sections.length;si++) {
    const sec=sections[si];
    let paras=sec.body.split(/\n{2,}/).map(p=>p.trim()).filter(p=>p.length>40);
    if(!paras.length) paras=[sec.body];
    const leaves=mergeToLeafNodes(paras);
    for(let ni=0;ni<leaves.length;ni++) {
      chunks.push({
        text:leaves[ni], context_window:sec.body, chunk_strategy:'hierarchical',
        parent_section:sec.heading, parent_page:pageTitle,
        section_index:si, node_index:ni, total_nodes:leaves.length, total_sections:sections.length
      });
    }
  }
  return chunks;
}

// ── Routing ───────────────────────────────────────────────────────
const cleaned = cleanText(page.content);
if (!cleaned || cleaned.split(/\s+/).length < 20) return [];

let raw;
if (page.doc_type === 'news_article') raw = sentenceWindowChunks(cleaned);
else if (page.doc_type === 'event') raw = fixedSizeChunks(cleaned);
else raw = hierarchicalChunks(cleaned, page.title);

return raw.map((rc, idx) => ({
  json: {
    text: rc.text,
    filename: page.url,
    file_hash: page.content_hash,
    source: page.url,
    title: page.title,
    doc_type: page.doc_type,
    date: page.date,
    site: 'jena-digital.de',
    context_window: rc.context_window || rc.text,
    chunk_strategy: rc.chunk_strategy,
    chunk_index: idx,
    total_chunks: raw.length,
    ...(rc.parent_section ? { parent_section: rc.parent_section } : {}),
    ...(rc.section_index !== undefined ? { section_index: rc.section_index } : {})
  }
}));
